SELECT s.*, ste.site_nm AS site_nm, mem.member_nm AS member_nm, cd_st.code_label AS save_type_cd_nm FROM pm_save s LEFT JOIN sy_site ste ON ste.site_id = s.site_id LEFT JOIN mb_member mem ON mem.member_id = s.member_id LEFT JOIN sy_code cd_st ON cd_st.code_grp = 'SAVE_TYPE' AND cd_st.code_value = s.save_type_cd
ORDER BY s.save_id ASC ORDER BY s.save_id DESC ORDER BY s.reg_date ASC ORDER BY s.reg_date DESC ORDER BY s.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT s.*, ste.site_nm AS site_nm, mem.member_nm AS member_nm, cd_st.code_label AS save_type_cd_nm FROM pm_save s LEFT JOIN sy_site ste ON ste.site_id = s.site_id LEFT JOIN mb_member mem ON mem.member_id = s.member_id LEFT JOIN sy_code cd_st ON cd_st.code_grp = 'SAVE_TYPE' AND cd_st.code_value = s.save_type_cd
ORDER BY s.save_id ASC ORDER BY s.save_id DESC ORDER BY s.reg_date ASC ORDER BY s.reg_date DESC ORDER BY s.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

