UPDATE pm_save
site_id = #{siteId}, member_id = #{memberId}, save_type_cd = #{saveTypeCd}, save_amt = #{saveAmt}, balance_amt = #{balanceAmt}, ref_type_cd = #{refTypeCd}, ref_id = #{refId}, expire_date = #{expireDate}, save_memo = #{saveMemo},
WHERE save_id = #{saveId}
